    @_mutmut_mutated(mutants_xǁTokenCostTrackerǁ_fire_alert__mutmut)
    def _fire_alert(
        self,
        tenant_id: str,
        budget_type: str,
        threshold_pct: float,
        current_spend: float,
        budget_limit: float,
    ) -> None:
        """Fire a budget alert."""
        alert = BudgetAlert(
            tenant_id=tenant_id,
            budget_type=budget_type,
            threshold_pct=threshold_pct,
            current_spend=current_spend,
            budget_limit=budget_limit,
        )

        self._alerts.append(alert)

        # Persist alert
        if self._conn is not None:
            try:
                self._conn.execute(
                    """INSERT INTO budget_alerts
                       (alert_id, tenant_id, budget_type, threshold_pct,
                        current_spend, budget_limit, timestamp, acknowledged)
                       VALUES (?, ?, ?, ?, ?, ?, ?, 0)""",
                    (
                        alert.alert_id,
                        alert.tenant_id,
                        alert.budget_type,
                        alert.threshold_pct,
                        alert.current_spend,
                        alert.budget_limit,
                        alert.timestamp,
                    ),
                )
                self._conn.commit()
            except sqlite3.Error:
                pass

        # Fire callbacks
        for callback in self._alert_callbacks:
            try:
                callback(alert)
            except Exception as exc:
                logger.error("Budget alert callback error: %s", exc)

        logger.warning(
            "Budget alert: %s %s at %.0f%% ($%.2f / $%.2f)",
            tenant_id,
            budget_type,
            threshold_pct,
            current_spend,
            budget_limit,
        )

